const isEntrega = (type) => {
  return type === "Entrega" || type === "REM_CARD_CUP" || type === "REM_CARD_MLC" || type === "REM_CASH_USD" || type === "REM_CASH_CUP";
}

export const balanceFactor = (type,am) => {
  if (isEntrega(type) || type ==="INVESTMENT_FOOD") {
    if(am>0){
      return -1;
    }else{
      return 1;
    }
  }
  else if (type ==="BTC" || type ==="MLC" || type ==="TRANSFER" || type ==="ADJUSTMENTS"  || type ==="DEBT"  || type ==="COMISION_AGENT" || type ==="DELIVERY_EXPS") {
    return 1;
  }
  else if (type ==="COMBO") {
    return 0;
  }
  else{
    return 0
  }
}








