export function handleDataSocket(eD) {
  let data = {}
  let sKey = getsectionKey();
  var parsedBase64Key = Base64Encode(sKey);
  let decrypkey = decryptV4(eD.k,parsedBase64Key);    
  let rslt = decryptV4(eD.d,decrypkey); 
  let city =  getCityZipCode();  

  if(isJson(rslt)){
    data = JSON.parse(rslt);
  }
  if(data.type === "InventoryUpdated"){
    if(!socketR[data.id]){
      socketR[data.id] = 1;
      let inView = getViewActive();
      if(inView===3){
        loadStockProductInv();
      }
      else if(inView===1){
        let fields = [
          "id","name","salePrice","isPublic","unit","imageUrl","ignoreStock","categoryID","rate",{N:"stock",f:["amount", "qty"]}
        ];
        let Qry2Inv = {
          query:"getStockProductQvaMarket",
          params:{
            isPublic: true,
            city: city
          },
          arraySerialization: isArraySerialization(),
          fields:fields
        };
        loadStockProduct(Qry2Inv,getDispatch());
      }
      else if(inView===2){
        const searchHash = window.location.hash.split('?')[1]?window.location.hash.split('?')[1]:null;
        const router = parseQuery(searchHash);
        let Qry2 = {
          params:{
            id:router.prodId
          },
          query:"getQueryProductsID",
        };
        fetchProductsID(Qry2,getDispatch());
      }
      else  if(inView===715){
        let fields = [
          "id","name","isPublic","unit","imageUrl","categoryID",{N:"stock",f:["amount", "qty"]}
        ];
        let Qry2Inv = {
          query:"getStockProductQvaMarket",
          params:{
            isPublic:true,
            city: city
          }, 
          arraySerialization: isArraySerialization(),
          fields:fields
        };
        loadStockProduct(Qry2Inv,getDispatch());
      }
    }
  }

  else if(data.type === "isPublicUpd"){     
    if(!socketR[data.id]){
      socketR[data.id] = 1;
      let inView = getViewActive();
      if(inView===1){
        fetchMrkProd();
        let fields = [
          "id","name","salePrice","isPublic","unit","imageUrl","ignoreStock","categoryID","rate",{N:"stock",f:["amount", "qty"]}
        ];
        let Qry2Inv = {
          query:"getStockProductQvaMarket",
          params:{
            isPublic: true,
            city: city
          },
          arraySerialization: isArraySerialization(),
          fields:fields
        };
        loadStockProduct(Qry2Inv,getDispatch());
      }
    }
  } 
  else if(data.type === "updateMovements"){ 
    if(!socketR[data.id]){
      socketR[data.id] = 1;
      let inView = getViewActive();
      if(inView===8){
        loadMovs();
      }
      else if(inView===9){
        fetchMovId();
      }
    }
  }
  else if(data.type === "addMovements"){
    if(!socketR[data.id]){
      socketR[data.id] = 1;
      let inView = getViewActive();
      if(inView===8){
        loadMovs();
      }
    }
  }
}




