export const calcDeliveries = async () => { 
  let _st = getStore();
  let mm = _st['deliveriesList'];
  const _form = getFormStore('deliveries_search') || {};
  let qry = _form["search"];

  let dlv = {};
  let dlvPn = {};
  let totals = {};



  ObjectKeys(mm).map((mv,ii)=>{


    let isValid = false;
    
    let _ord = mm[mv]["serial"] && mm[mv]["serial"].toString().toLowerCase();
    
      if(qry){
        let _qr = qry && qry.toLowerCase()?qry.toString().toLowerCase():"";
        let _idPl = ObjectKeys(mm[mv]["place"])[0];
        let plc =mm[mv]["place"] && mm[mv]["place"][_idPl] && mm[mv]["place"][_idPl]["formatted_address"].toString().toLowerCase();
        let _hasPrdNm = false;
        let _hasTyp = plc && plc.indexOf(_qr)>=0 ;
        let _has_ord = _ord && _ord.indexOf(_qr)>=0 ;
        if(_hasTyp ||  _hasPrdNm || _has_ord){
          isValid = true;
        }
      }else{
        isValid = true;
      }
      if(isValid){
        if(mm[mv]["delivery"]){
          dlv[mv] = mm[mv]
          if(!totals["delivery"]){
            totals["delivery"] = 1
          }else{
            totals["delivery"] += 1
          }
        }
        else{
          dlvPn[mv] = mm[mv]
          if(!totals["pending"]){
            totals["pending"] = 1
          }else{
            totals["pending"] += 1
          }
        }
      }
  })

  
  updStore('deliveriesListbyAddress',groupbyAddress(dlv))
  updStore('deliveriesPendingbyAddress',groupbyAddress(dlvPn))
  updStore('deliveryTotals',totals)
  updObserveChanges();
}





export function groupbyAddress(obj) {
  let h = {}
  //let _1d = 86400000;
  obj && ObjectKeys(obj).map((d)=>{
      if(d){ 
          let _ddtId = ObjectKeys(obj[d]["place"])[0];
          if(!h[_ddtId]){
              h[_ddtId] = {};
              h[_ddtId]["serials"] = {}
              h[_ddtId]["address"] = obj[d]["place"][_ddtId]["formatted_address"];
              h[_ddtId]["location"] = obj[d]["place"][_ddtId]["location"];
          }
          h[_ddtId]["serials"][d]=obj[d];
      } 
  })
  return h;
}




